sp_widget.client_script:
api.controller=function ($scope, $location, $rootScope, spUtil, spModal, spAriaFocusManager, $timeout) {

	var c = this;

	var search = $location.search();
	if(c.data.sys_id && c.data.sys_id != -1 &&
		 search.sys_id != c.data.sys_id){
		// data table is being set to row 1 by this widget.
		// broadcast to other widgets without forcing full page reload
		$location.search("sys_id", c.data.sys_id).search("selTab", c.data.selTab).search("page_index", c.data.page_index).search("spa",1);
	}
	var urlParams = new URLSearchParams(window.location.search);
	var x = urlParams.get('table');

	c.refresh = function () {
		$scope.server.update();
		c.activeTab = c.data.tabs[0].tabName;
	};
	// STRY0125255 - STRY0123997
	if(c.data.selTab){
		c.activeTab =c.data.selTab;
	} else {
		c.activeTab = c.data.tabs[0].tabName;
	}

	var tab = {
		className: "active"
	};

	$scope.openModalNewPocessTemplate = function (sys_id_Modal) {
		var table = 'x_153465_discovert_discover_routing_template';

		var shared = { 
			fields: {
				sys_id: {
					value: -1, 
					displayValue: "", 
					sys_mandatory: false, 
					mandatory: false, 
					placeholder: "", 
					readonly: false
				}
			}
		};
		spModal.open({
			title: 'New Template',
			backdrop:'static',
			widget: 'discovertasker-formtab',
			widgetInput: {
				table: table,
				sys_id: -1,
				// DFCT0010771
				view: 'sp',
				// DFCT0010635
				omitHeader: 'true',				
				isModal: true,
				// DFCT0010771
				query: ""
			},
			shared: shared,
			size: 'lg',
			buttons: [''],
			// 2.8 | 2022-01-13 | mmcc | STRY0110656 - UI- Fixed Header and Button Bars on ALL Modals and lists
			footerStyle: {
				'display': 'none'
			}
		}).then(function() {
			// STRY0127096 - create_template
			$scope.data.getTemplateInfo = true;
			$scope.data.templateId = shared.fields.sys_id.value;
			spUtil.update($scope).then(function(data) {
				spUtil.addInfoMessage(data.newTemplateMessage);
				$scope.data.getTemplateInfo = false;
			});

		});
	};

	c.showTab = function (tab, e) {
		c.activeTab = tab.tabName;
		target = e.target;
		$(target).parents('.nav-tabs').find('li').removeClass('active');
		$(target).parents('li').addClass('active');
		$rootScope.$broadcast("declareActiveTab", c.activeTab);
	};

	// 2.7.0 | 2021-05-21 | mmcc | STRY0099596 Record Watcher on Template Count not Updating; emit sends rowCount in params, no need for .Deleted or .Added
	function _onDiscoverListItem (event, params) {
		c.data.tabs.forEach(function(tab) {
			if(tab.table == params.table && tab.filter == params.filter ) {
				tab.count = params.rowCount;
			}
		});
	}

	// STRY0125255 - STRY0123997 - item selected, update url with selected tab and page index
	function _onDataTableClick(e, parms) {
		var page_index = 1;
		for (var i in $scope.data.tabs) {

			var tab = $scope.data.tabs[i];			
			if(c.activeTab==tab.tabName){
				if(tab.page_index){
					page_index = tab.page_index;
				}
				$location.search("p", page_index).search("selTab", c.activeTab).search("spa",1);
			}
		}
	}

	// STRY0125255 - STRY0123997
	function _pageIndexUpdated(event, e) {
		if (e && e.title) {
			for (var i in $scope.data.tabs) {
				var tab = $scope.data.tabs[i];
				if(e.title == tab.tabTitle && tab.page_index != e.page_index){
					tab.page_index = e.page_index;
				}
			}
		}
	}	

	// STRY0120403 if filter changed, then record count will change and we will need to receive an updated count
	function _countUpdated(event, e) {
		if (e && e.title) {
			for (var i in $scope.data.tabs) {
				var tab = $scope.data.tabs[i];
				if(e.title == tab.tabTitle && tab.count != e.count){
					tab.count = e.count;
				}
			}
		}
	}

	// STRY0127096 - unregister all event watchers
	var unregister_discovertasker_widget_data_table_update_count = $scope.$on("discovertasker-widget-data-table-update_count", _countUpdated);
	var unregister_discovertasker_widget_data_table_update_page_index = $scope.$on("discovertasker-widget-data-table-update_page_index", _pageIndexUpdated);
	var unregister_dataTableClick = $rootScope.$on('dataTableClick', _onDataTableClick);
	var unregister_sp_DiscoverListItem = $scope.$on('sp.DiscoverListItem', _onDiscoverListItem);

	// STRY0127096 - unregister all event watchers
	$scope.$on("$destroy", function() {
		unregister_discovertasker_widget_data_table_update_count();
		unregister_discovertasker_widget_data_table_update_page_index();
		unregister_dataTableClick();
		unregister_sp_DiscoverListItem();
	});	


};

