sp_widget.script:
// Copyrights belong to Discover Technologies LLC. © 2021 Discover Technologies LLC
// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// UPDATED BY: KARINA TORRES
//------------------------------------------------------------------------------------------------------------------------
//
// 2.7.0 | 2021-05-21 | mmcc | STRY0099596 Record Watcher on Template Count not Updating. 
// 											Removed :: from {{tab.tabTitle}} and {{tab.count}} in HTML
// 											emit sends rowCount in params, no need for .Deleted or .Added
//											Change made in HTML and Client controller
// 2.7.0 | 2021-11-14 | raj  | DFCT0010635 - Remove "Context Menu" from all "New" forms in the Tasker system
//											Changes in Client script.
// 2.7.3 | 2022-04-27 | raj  | DFCT0010771 - Opening "Template" modal causes "Warnings" in log: "Invalid query detected, please check logs for details [Unknown field null in table [table]"
//											Changes in Client script.
// 2.8   | 2022-01-13 | mmcc | STRY0110656 - UI- Fixed Header and Button Bars on ALL Modals and lists
//                                      In Client controller, added code for footerstyle display none
//                                      Changes made in Client controller
// 2.8 | 2022-05-13 | mmcc | DFCT0010887 - New button is gone from Template List page
// 2.8 | 2022-05-13 | mmcc | DFCT0010911 - Templates modal  forms are NOT displaying at ALL
//                                      In HTML, moved Show Inactive Templates input and span tags under class="panel-heading
//                                      Changes made in HTML
// 2.8 | 2022-06-17 | mmcc | DFCT0010888 - Zoom buttons are Not always correctly displayed on the Template List page
//                                      In HTML, updated panel panel- to stick at the top and flex column, updated panel-heading to flex, justify between and have a
//                                        height of 75px, updated panel-body to flex column and grow, updated cm-tab-content to flex row, grow and justify center,
//                                        updated div for ngif=tab.dataTableWidget to flex column and grow, wrapped the anchor New button in a div to flex row, justify
//                                        end and have some padding.
//                                      In CSS, comment out .panel with border 0, update .cm-right-pane { .cm-widget-tabs { .nav-tabs {, to use just border-bottom: none,
//                                      updated cm-widget-body padding-right to 5px and padding-bottom to 0.
//                                      In Server script, in widgetParams added isBifold.
//                                      Changes made in HTML, CSS and Server script
// 2.8.0 | 2022-07-14 | raj  | STRY0125255 - Template Layout- Add "Template List Page" as an option
// 2.8.0 | 2022-07-14 | raj  | STRY0123997 - Templates- System will remember Template Record when switching from any Template Page to the Template List
// 2.8.0 | 2022-07-28 | raj  | DFCT0011119 - Top Template Record in the list view is NOT selected upon initial page load of the "Template page"
// 2.8 | 2022-08-01 | mmcc | DFCT0011122 - Page Task Requests needs to match the standard layout for flexing header-body-footer
//                                      In HTML, reorder CSS selectors to have panel names first better precedence.
//                                      In CSS, added .dtech-border-bottom-1px-solid-ddd.
//                                      In Server script, added convertToBool().
//                                      Changes made in HTML, CSS and Server script.
// 2.8.0 | 2022-08-12 | raj  | STRY0127096 - Stretch- New Template page- Remove messaging "Click here to build your Template" after creating Template - added an action name to be used later
//																			Changes in Client Script, also updated all $on events to destroy them on close of widget
//
//------------------------------------------------------------------------------------------------------------------------

(function($sp, input, data, options, gs) {
	// STRY0074534 Template Admins can read any template
	var UserPermissions = new UserInfoScripts();

	// DFCT0011119 - set standard layout
	main();
	function main(){
    data.page_id = "";
    data.showInactiveProcess = false;
    if (input){
			data.showInactiveProcess = input.showInactiveProcess;
			if(input.getTemplateInfo==true){
				// set template name and parent task def
				_getTemplateInfo();
				return;
			}
		}


		// STRY0125255 - STRY0123997
		data.selTab = $sp.getParameter("selTab");
		data.p = $sp.getParameter("p");
    data.page_index = parseInt(data.p || 1);
		// DFCT0011119 - get sys_id
		data.sys_id = $sp.getParameter('sys_id');

		data.window_size = $sp.getValue('maximum_entries') || 10;
		data.window_start = (data.page_index * data.window_size);
		data.window_end = (((data.page_index + 1) * data.window_size));

		// DFCT0011119
		data.bifold = (input || {}).bifold || (options || {}).bifold || false;

		// 2.8 | 2022-08-01 | mmcc | DFCT0011122 - Page Task Requests needs to match the standard layout for flexing header-body-footer; added
		convertToBool(['bifold']);

		data.tabs = _loadTabs();

	}

	function _loadTabs() {

    var link = '';
    var widgetParams;
    var tabs = [];
    var links = ['link1', 'link2', 'link3', 'link4', 'link5'];
    for (var i = 0; i < links.length; i++) {
        link = options[links[i]];
        // overwriting filter in here...
        if (link) {
            var tab = {};
            widgetParams = _getTabData(link);
            // override filter calling JS
            switch (widgetParams.view) {
                case 'MyProcess':
                    // override the my filter in the page with javascript
                    widgetParams.filter = new tasking_System_Settings_Scripts().getMyTemplateFilter(false);
                    break;
                case 'OUProcess':
                    // override the ou filter in the page with javascript
                    widgetParams.filter = new tasking_System_Settings_Scripts().getOUTemplateFilter(false);
									break;
                case 'GlobalProcess':
                    // override the ou filter in the page with javascript
                    widgetParams.filter = new tasking_System_Settings_Scripts().getGlobalTemplateFilter(false);
                    break;
            }
						if(data.showInactiveProcess == false){
							widgetParams.filter += '^u_active=true';
						}
            if (widgetParams.table) {
                tab.table = widgetParams.table;
                tab.tabTitle = widgetParams.title;
								tab.o = widgetParams.o;
								tab.d = widgetParams.d;
                tab.filter = widgetParams.filter;
                tab.view = widgetParams.view;
                tab.page_id = widgetParams.page_id;
                tab.tabName = 'tab' + i;
                tab.role = widgetParams.role;
								// STRY0074523  need to check for more than one role here
								var tabVisible = false;
								// STRY0079396 - corrected template permissions
								if(UserPermissions.userHasProcessTemplateAdminRights()){
									tabVisible = true;
								} else if (tab.role=='template_ou' && UserPermissions.userIsOUTemplateDesigner()){
										tabVisible = true;
								} else	if(gs.hasRole(tab.role)){
									tabVisible = true;
								}
								tab.visible = tabVisible; // gs.hasRole(tab.role);// || UserPermissions.userHasProcessTemplateAdminRights();
                tab.count = _getTableCountbyFilter(tab.table, tab.filter);
                tab.className = '';
            }
					tab.widgetParams = widgetParams;
					if (tab.visible)
						tabs.push(tab);

        }
    }
		_findActiveTab(tabs);

		// create the tabs with the page_index set
		for (var t2 in tabs){
			var tab3 = tabs[t2];
			tab3.dataTableWidget = $sp.getWidget('discovertasker-widget-data-table', tab3.widgetParams); //widget-data-table	
		}

		return tabs;

	}

  function _findActiveTab(tabs){
		if (tabs.length > 0){
			// STRY0125255 - STRY0123997
			if(data.selTab){
				// find selected tab and mark active
				for (var t in tabs){
					var tab1 = tabs[t];
					if(tab1.tabName == data.selTab){
						// STRY0125255 - STRY0123997 set the page index for hte selected template
						if(data.page_index){
							tab1.widgetParams.p=data.page_index;	
						}
						tab1.className = 'active';
						break;
					}
				}
			} else{
				if(!_getFirstTabAndId(tabs)){
					tabs[0].className = 'active';	
				}

			}
		}
	}

	function _getFirstTabAndId(tabs){
		var foundItem = false;
		for (var t in tabs){
			var tab1 = tabs[t];
			if(tab1.count > 0){
				tab1.className = 'active';
				tab1.selectedId = _getFirstItemByFilter(tab1);
				data.selTab = tab1.tabName;
				data.page_index = 1;
				foundItem = true;
				break;
			}
		}
		return foundItem;
	}


	function _getFirstItemByFilter(tab){
		var table = tab.table;
		var filter = tab.filter;

		var foundId;
		var gr_template = new GlideRecord(table);
		gr_template.addEncodedQuery(filter);
		if (tab.o) {
			if (tab.d == "asc"){
				gr_template.orderBy(tab.o);
			} else {
				gr_template.orderByDesc(tab.o);
			}
		}		

		// only count active processes
		if (table == 'x_153465_discovert_discover_routing_template' && !data.showInactiveProcess) {
			gr_template.addQuery('u_active', true);
		}
		gr_template.query();

		if (gr_template.next()) {
			foundId = gr_template.getUniqueValue();
			data.sys_id = foundId;
			data.process_level = {
				value: gr_template.getValue("process_level"),
				display_value: gr_template.getDisplayValue("process_level")
			};
			data.template_name = {
				value: gr_template.getValue("template_name"),
				display_value: gr_template.getDisplayValue("template_name")
			};
		}

		return foundId;
	}

	function _getTabData(link) {
		var table = _getParameterByName(link, 'table');
		var view = _getParameterByName(link, 'view') || 'sp';
		if (!table) {
			return;
		}


		var widgetParams = {
			table: table,
			o: _getParameterByName(link, 'o') || $sp.getValue('order_by'),
			d: _getParameterByName(link, 'd') || $sp.getValue('order_direction'),
			p: _getParameterByName(link, 'p') || 1,
			view: view,
			fields: $sp.getListColumns(table, view),
			page_id: _getParameterByName(link, 'page') || data.page_id || 'form',
			show_keywords: _getParameterByName(link, 'show_keywords'),
			show_breadcrumbs: _getParameterByName(link, 'show_breadcrumbs'),
			show_new: _getParameterByName(link, 'show_new'),
			filter: _getParameterByName(link, 'filter'),
			enable_filter: _getParameterByName(link, 'enable_filter'),
			window_size: data.window_size,
			bifold: data.bifold, // 2.8 | 2022-06-17 | mmcc | DFCT0010888 - Zoom buttons are Not always correctly displayed on the Template List page
			title: gs.getMessage(_getParameterByName(link, 'title')),
			role: gs.getMessage(_getParameterByName(link, 'role')),
			showInactiveProcess: data.showInactiveProcess
		};
		return widgetParams;
	}

	function _getParameterByName(url, name) {
		name = name.replace(/[\[\]]/g, "\\$&");
		var regex = new RegExp("[?&]" + name + "(=([^&#]*)|&|#|$)"),
				results = regex.exec(url);
		if (!results) return null;
		if (!results[2]) return '';
		return decodeURIComponent(results[2].replace(/\+/g, " "));
	}


	function _getTableCountbyFilter(table, filter) {
		var count;
		var ga = new GlideAggregate(table);
		ga.addEncodedQuery(filter);
		ga.addAggregate('COUNT');

		// only count active processes
		if (table == 'x_153465_discovert_discover_routing_template' && !data.showInactiveProcess) {
			ga.addQuery('u_active', true);
		}
		ga.query();

		if (ga.next()) {
			count = parseInt(ga.getAggregate('COUNT'));

		}
		if (ga == null)
			return;
		else return count;
	}

	function _getTemplateInfo(){
		var gr_template = new GlideRecord("x_153465_discovert_discover_routing_template");
		if(gr_template.get(input.templateId)){
			data.newTemplateMessage = gs.getMessage("Tasker - Template created message with Template Name {0} and Top Template Task id {1}",
											[gr_template.template_name, gr_template.parent_task_def]);
		}
	}

	// 2.8 | 2022-08-01 | mmcc | DFCT0011122 - Page Task Requests needs to match the standard layout for flexing header-body-footer; added
	function convertToBool(names) {
		names.forEach(function(name) {
			data[name] = data[name] == true || data[name] == 'true';
		});
	}

})($sp, input, data, options, gs);
